        ds_Grid1.setCellData(j, "chassisEqCd", scwin.hid_chassisEqCd);
        ds_Grid1.setCellData(j, "chassisNo", scwin.hid_chassisNo);
        ds_Grid1.setCellData(j, "vehclKndCd", scwin.hid_vehclKndCd);
