scwin.f_GateinProcess = async function (p_gubun) {
  let gridChkYn = 0;
  let copinoAutoSndYn = 0;
  scwin.copinoManualSndYn = 0;
  for (let i = 0; i < ds_Grid1.getRowCount(); i++) {
    if (ds_Grid1.getCellData(i, "gridChkBox") == "1" || ds_Grid1.getCellData(i, "gridChkBox") == "T") gridChkYn++;
    if ((ds_Grid1.getCellData(i, "gridChkBox") == "1" || ds_Grid1.getCellData(i, "gridChkBox") == "T") && ds_Grid1.getCellData(i, "cntrNo") == "") {
      if (ds_Grid1.getCellData(i, "cntrNoYn") == "0" && ds_Grid1.getCellData(i, "crryinoutClsCd") == scwin.CRRYINOUT_CLS_CD_OUT) {} else {
        await $c.win.alert($p, i + 1 + "번째 데이터에서 컨테이너번호는 필수 입력 항목입니다.");
        return;
      }
    }
    if ((ds_Grid1.getCellData(i, "gridChkBox") == "1" || ds_Grid1.getCellData(i, "gridChkBox") == "T") && ds_Grid1.getCellData(i, "gateinDth").length != 12) {
      await $c.win.alert($p, i + 1 + "번째 데이터에서 반입일시를 확인 하십시요.");
      return;
    }
    if ((ds_Grid1.getCellData(i, "gridChkBox") == "1" || ds_Grid1.getCellData(i, "gridChkBox") == "T") && ds_Grid1.getCellData(i, "chkFlag") == "C") {
      await $c.win.alert($p, i + 1 + "번째 항목은 이미 반입완료된 항목 입니다.");
      return;
    }
    if ((ds_Grid1.getCellData(i, "gridChkBox") == "1" || ds_Grid1.getCellData(i, "gridChkBox") == "T") && ed_wrkPlCd.getValue() == "6C01" && ds_Grid1.getCellData(i, "socYn") == "1" && ds_Grid1.getCellData(i, "odrKndCd") != scwin.ODR_KND_CD_IMP_CVSSL_CNTR_ODR) {
      await $c.win.alert($p, i + 1 + "번째 항목은 SOC컨테이너이며 반입할 수 없습니다. SOC구분을 수정하시고 반입하세요.");
      return;
    }
    if (p_gubun == "Auto" && ds_Grid1.getCellData(i, "preInfoSndYn") == "1" && ds_Grid1.getCellData(i, "dptArvWrkPlClsCd") != scwin.WRK_PL_CLS_CD_CY && ds_Grid1.getCellData(i, "selfClsCd") != scwin.SELF_CLS_CD_SELF_CRRYOUT && (ds_Grid1.getCellData(i, "gridChkBox") == "1" || ds_Grid1.getCellData(i, "gridChkBox") == "T")) {
      ds_Grid1.setCellData(i, "copinoAutoSndYn", "1");
      copinoAutoSndYn = 1;
    }
    if (p_gubun == "Manual" && ds_Grid1.getCellData(i, "preInfoSndYn") == "1" && ds_Grid1.getCellData(i, "dptArvWrkPlClsCd") != scwin.WRK_PL_CLS_CD_CY && ds_Grid1.getCellData(i, "selfClsCd") != scwin.SELF_CLS_CD_SELF_CRRYOUT && (ds_Grid1.getCellData(i, "gridChkBox") == "1" || ds_Grid1.getCellData(i, "gridChkBox") == "T")) {
      scwin.copinoManualSndYn++;
      scwin.copinoRowPosition = i;
    }
    if (p_gubun == "Manual" && ds_Grid1.getCellData(i, "dptArvWrkPlClsCd") == "6M14" && ds_Grid1.getCellData(i, "selfClsCd") != scwin.SELF_CLS_CD_SELF_CRRYOUT && (ds_Grid1.getCellData(i, "gridChkBox") == "1" || ds_Grid1.getCellData(i, "gridChkBox") == "T")) {
      let arvWrkPlCd = ds_Grid1.getCellData(i, "dptArvWrkPlCd");
      dma_preInfoSndYnParam.set("sysCd", "StationEachRailroadResultsEBC");
      dma_preInfoSndYnParam.set("queryId", "RetrievePreInfoSndYnForJSP");
      dma_preInfoSndYnParam.set("param1", arvWrkPlCd);
      await $c.sbm.execute($p, sbm_RetrievePreInfoSndYn);
      if (ds_preInfoSndYn.getCellData(0, "code") == "1") {
        scwin.copinoManualSndYn++;
        scwin.copinoRowPosition = i;
      }
    }
  }
  if (p_gubun == "Auto" && copinoAutoSndYn == 0) {
    await $c.gus.cfAlertMsg($p, "COPINO 전송 대상이 없습니다.");
    return;
  }
  if (p_gubun == "Manual") {
    if (gridChkYn > 1) {
      await $c.gus.cfAlertMsg($p, "M/S인 경우 한건만 선택 할 수 있습니다.");
      return;
    }
    if (scwin.copinoManualSndYn == 0) {
      await $c.gus.cfAlertMsg($p, "선택하신 사항중 COPINO 전송대상이 포함되어 있지 않습니다.");
      return;
    }
  }
  if (gridChkYn == 0) {
    await $c.gus.cfAlertMsg($p, "선택된 사항이 없습니다.");
    return;
  }
  if (ds_Grid1.getUpdatedIndex().length == 0) {
    await $c.gus.cfAlertMsg($p, "선택된 사항이 없습니다.");
  } else {
    let confirmResult = await $c.win.confirm($p, "Gate In 처리 하시겠습니까?");
    if (confirmResult) {
      await $c.sbm.execute($p, sbm_GateIn);
    }
  }
};
