scwin.gr_Grid1_oncellclick = async function (rowIndex, columnIndex, columnId) {
  let Row = rowIndex;
  let makeString = "";
  if (ds_Grid1.getCellData(Row, "leaseYn") == "1") {
    makeString = makeString + "LES : Y";
  } else {
    makeString = makeString + "LES : N";
  }
  if (ds_Grid1.getCellData(Row, "socYn") == "1") {
    makeString = makeString + " , SOC : Y";
  } else {
    makeString = makeString + " , SOC : N";
  }
  makeString = makeString + " , TERM : " + ds_Grid1.getCellData(Row, "term");
  if (ds_Grid1.getCellData(Row, "offRtrnClsCd") == "1") {
    makeString = makeString + " , OFF반납 : DOOR반납";
  } else if (ds_Grid1.getCellData(Row, "offRtrnClsCd") == "2") {
    makeString = makeString + " , OFF반납 : CY반납";
  } else if (ds_Grid1.getCellData(Row, "offRtrnClsCd") == "3") {
    makeString = makeString + " , OFF반납 : 부두반납";
  } else {
    makeString = makeString + " , OFF반납 : " + ds_Grid1.getCellData(Row, "offRtrnClsCd");
  }
  makeString = makeString + " , RMK : " + ds_Grid1.getCellData(Row, "rmk");
  // TODO: sp_rmk 표시 처리

  if (Row >= 0 && columnId == "cntrTypCd") {
    if (ds_Grid1.getCellData(Row, "cntrTypCd") != "RF") return;
    if (ds_Grid1.getCellData(Row, "cntrNo") == "") {
      await $c.gus.cfAlertMsg($p, "컨테이너번호를 입력하세요.");
      return;
    }
    let url = "/ui/ds/op/wrkrslts/cywrkrslts/op_301_01_05p2.xml";
    await $c.win.openPopup($p, url, {
      width: 300,
      height: 200,
      modal: true,
      data: {}
    });
  } else if (Row >= 0 && columnId == "gridChkBox") {
    if (ds_Grid1.getCellData(Row, "gridChkBox") == "1" || ds_Grid1.getCellData(Row, "gridChkBox") == "T") {
      let d = new Date().getMinutes().toString();
      if (d.length == 1) d = "0" + d;
      let nowDate = WebSquare.date.getCurrentServerDate("yyyyMMddHH");
      if (ds_Grid1.getCellData(Row, "crryinoutClsCd") == scwin.CRRYINOUT_CLS_CD_OUT && ds_Grid1.getCellData(Row, "cntrNoYn") == "0") {
        if (ds_Grid1.getCellData(Row, "gateinDth") == "") {
          ds_Grid1.setCellData(Row, "gateinDth", nowDate + d);
        }
        return;
      }
      if (ds_Grid1.getCellData(Row, "chkFlag") == "C") {
        return;
      }
      if (ds_Grid1.getCellData(Row, "cntrNo") == "") {
        await $c.gus.cfAlertMsg($p, "컨테이너번호가 없습니다.");
        ds_Grid1.setCellData(Row, "gridChkBox", "0");
        return;
      }
      if (ds_Grid1.getCellData(Row, "vehclNo") == "") {
        await $c.gus.cfAlertMsg($p, "차량번호가 없습니다.");
        ds_Grid1.setCellData(Row, "gridChkBox", "0");
        return;
      }
      if (ds_Grid1.getCellData(Row, "chassisNo") == "") {
        if (ds_Grid1.getCellData(Row, "selfSpotClsCd") == "1" || ds_Grid1.getCellData(Row, "selfClsCd") == scwin.SELF_CLS_CD_SELF_CRRYOUT) {} else {
          await $c.gus.cfAlertMsg($p, "샤시 번호가 없습니다.");
          ds_Grid1.setCellData(Row, "gridChkBox", "0");
          return;
        }
      }
      if (ds_Grid1.getCellData(Row, "eqCd") == "") {
        if (ds_Grid1.getCellData(Row, "selfSpotClsCd") == "1" || ds_Grid1.getCellData(Row, "selfClsCd") == scwin.SELF_CLS_CD_SELF_CRRYOUT) {} else {
          await $c.gus.cfAlertMsg($p, "장비코드가 없습니다.");
          ds_Grid1.setCellData(Row, "gridChkBox", "0");
          return;
        }
      }
      if (ds_Grid1.getCellData(Row, "chassisEqCd") == "") {
        if (ds_Grid1.getCellData(Row, "selfSpotClsCd") == "1" || ds_Grid1.getCellData(Row, "selfClsCd") == scwin.SELF_CLS_CD_SELF_CRRYOUT) {} else {
          await $c.gus.cfAlertMsg($p, "샤시장비코드가 없습니다.");
          ds_Grid1.setCellData(Row, "gridChkBox", "0");
          return;
        }
      }
      if (ds_Grid1.getCellData(Row, "fullEmptyClsCd") == "F" && (ds_Grid1.getCellData(Row, "odrKndCd") == scwin.ODR_KND_CD_IMP_CVSSL_CNTR_ODR || ds_Grid1.getCellData(Row, "odrKndCd") == scwin.ODR_KND_CD_IMP_GNRL_CNTR_ODR || ds_Grid1.getCellData(Row, "odrKndCd") == scwin.ODR_KND_CD_EXP_CVSSL_CNTR_ODR || ds_Grid1.getCellData(Row, "odrKndCd") == scwin.ODR_KND_CD_EXP_GNRL_CNTR_ODR) && ds_Grid1.getCellData(Row, "sealNo") == "") {
        await $c.gus.cfAlertMsg($p, "SEAL NO가 없습니다.");
        ds_Grid1.setCellData(Row, "gridChkBox", "0");
        return;
      }
      if (ds_Grid1.getCellData(Row, "cntrNoChangeYn") == "2") {
        if (ds_Grid1.getCellData(Row, "gateinDth") == "") {
          ds_Grid1.setCellData(Row, "gateinDth", nowDate + d);
        }
        return;
      }
      if (ds_Grid1.getCellData(Row, "arrvlportDtm").length != 12) {
        await $c.gus.cfAlertMsg($p, "입항일시가 없습니다. 또는 유효하지 않은 컨테이너 번호입니다. 컨테이너 번호를 확인하십시요.");
        ds_Grid1.setCellData(Row, "gridChkBox", "0");
        return;
      }
      if (ds_Grid1.getCellData(Row, "cmpstcrgKndCd") == scwin.CMPSTCRG_KND_CD_DD && !(ds_Grid1.getCellData(Row, "odrKndCd") == scwin.ODR_KND_CD_EXP_GNRL_CNTR_ODR && ds_Grid1.getCellData(Row, "wrkStpCd") == scwin.WRK_STP_CD_RETRV)) {
        await $c.gus.cfAlertMsg($p, "직도어 복화 입니다. 직도어 복화인 경우 C4 오더 DOOR 회수만 수행 하시기 바랍니다.");
        ds_Grid1.setCellData(Row, "gridChkBox", "0");
        return;
      }
      dma_managementItemParam.set("crryinoutIntendNo", ds_Grid1.getCellData(Row, "crryinoutIntendNo"));
      dma_managementItemParam.set("arrvlportDt", ds_Grid1.getCellData(Row, "arrvlportDtm"));
      dma_managementItemParam.set("cntrNo", ds_Grid1.getCellData(Row, "cntrNo"));
      dma_managementItemParam.set("crryinoutClsCd", ds_Grid1.getCellData(Row, "crryinoutClsCd"));
      dma_managementItemParam.set("odrNo", ds_Grid1.getCellData(Row, "odrNo"));
      dma_managementItemParam.set("cntrSeq", ds_Grid1.getCellData(Row, "cntrSeq"));
      dma_managementItemParam.set("wrkPathSeq", ds_Grid1.getCellData(Row, "wrkPathSeq"));
      dma_managementItemParam.set("wrkStpSeq", ds_Grid1.getCellData(Row, "wrkStpSeq"));
      dma_managementItemParam.set("transWrkIndictNo", ds_Grid1.getCellData(Row, "transWrkIndictNo"));
      dma_managementItemParam.set("cmpstcrgKndCd", ds_Grid1.getCellData(Row, "cmpstcrgKndCd"));
      dma_managementItemParam.set("eqCd", ds_Grid1.getCellData(Row, "eqCd"));
      dma_managementItemParam.set("logisLnkEqCd", ds_Grid1.getCellData(Row, "chassisEqCd"));
      await $c.sbm.execute($p, sbm_RetrieveManagementItem);
    }
  }
};
